import{_ as a,o as n,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"CAT-09. 기획 & 전략 문서","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/planning-strategy.md","filePath":"hermes/benchmark/planning-strategy.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/planning-strategy.md"};function i(c,s,t,o,r,h){return n(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="cat-09-기획-전략-문서" tabindex="-1">CAT-09. 기획 &amp; 전략 문서 <a class="header-anchor" href="#cat-09-기획-전략-문서" aria-label="Permalink to &quot;CAT-09. 기획 &amp; 전략 문서&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 사업 기획서, 제안서, 예산안 등 <strong>의사결정 지원 문서</strong>를 논리적이고 설득력 있게 작성할 수 있는가?</p></blockquote><h2 id="이-카테고리가-중요한-이유" tabindex="-1">이 카테고리가 중요한 이유 <a class="header-anchor" href="#이-카테고리가-중요한-이유" aria-label="Permalink to &quot;이 카테고리가 중요한 이유&quot;">​</a></h2><p>기획·전략 문서는 단순 글쓰기가 아니다. <strong>데이터 해석 → 논리 구성 → 설득력 있는 결론</strong>까지 이어지는 종합적 사고 능력이 필요하다.<br> 에이전트가 &quot;그럴듯한 문서&quot;를 만드는 것과 &quot;실제로 의사결정에 활용 가능한 문서&quot;를 만드는 것은 전혀 다르다.</p><h2 id="난이도-범례" tabindex="-1">난이도 범례 <a class="header-anchor" href="#난이도-범례" aria-label="Permalink to &quot;난이도 범례&quot;">​</a></h2><table tabindex="0"><thead><tr><th>레벨</th><th>의미</th><th>예상 소요</th></tr></thead><tbody><tr><td>⭐</td><td>기초 — 정해진 프레임워크, 단일 문서</td><td>2~3분</td></tr><tr><td>⭐⭐</td><td>중급 — 분석 필요, 다면적 고려</td><td>3~5분</td></tr><tr><td>⭐⭐⭐</td><td>고급 — 전략적 판단, 복합 이해관계</td><td>5~10분</td></tr></tbody></table><hr><h2 id="ps-01-신규-사업-제안서" tabindex="-1">PS-01. 신규 사업 제안서 ⭐⭐⭐ <a class="header-anchor" href="#ps-01-신규-사업-제안서" aria-label="Permalink to &quot;PS-01. 신규 사업 제안서 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>신규 사업 아이템을 경영진에게 설득하는 제안서. 시장 분석, 수익 모델, 리스크까지 포함.</p><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>신규 사업 제안서를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>아이디어: </span></span>
<span class="line"><span>중소기업 대상 &quot;AI 기반 회계 자동화 SaaS&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경 정보:</span></span>
<span class="line"><span>- 우리 회사: 중견 SI 기업 (매출 500억, 직원 300명)</span></span>
<span class="line"><span>- 기존 사업: 대기업 SI 프로젝트 위주 (경쟁 심화, 마진 하락)</span></span>
<span class="line"><span>- 시장 기회: 중소기업 200만개 중 회계 소프트웨어 사용률 30% 미만</span></span>
<span class="line"><span>- 경쟁: 더존, 위하고 등 기존 회계 SW + 최근 AI 스타트업 등장</span></span>
<span class="line"><span>- 우리 강점: 기업 회계 도메인 지식 20년, 기존 고객사 네트워크</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제안서 구성:</span></span>
<span class="line"><span>1. Executive Summary (1페이지)</span></span>
<span class="line"><span>   - 왜 지금인가, 핵심 가치 제안, 예상 수익</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 시장 분석</span></span>
<span class="line"><span>   - TAM/SAM/SOM 산정 (논리적 근거 포함)</span></span>
<span class="line"><span>   - 경쟁 환경 (기존 vs 신규, 우리의 포지셔닝)</span></span>
<span class="line"><span>   - 트렌드: AI 회계 시장 성장률</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 제품 개요</span></span>
<span class="line"><span>   - 핵심 기능 3~5가지</span></span>
<span class="line"><span>   - 기존 솔루션과의 차별점</span></span>
<span class="line"><span>   - 기술 스택 (간략히)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 비즈니스 모델</span></span>
<span class="line"><span>   - 가격 정책 (3 tier: Basic/Pro/Enterprise)</span></span>
<span class="line"><span>   - 예상 고객 획득 비용(CAC), 생애가치(LTV)</span></span>
<span class="line"><span>   - BEP(손익분기) 시점 예측</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Go-to-Market 전략</span></span>
<span class="line"><span>   - 1차 타깃 고객 (구체적 세그먼트)</span></span>
<span class="line"><span>   - 영업 채널 (기존 고객사 크로스셀, 온라인, 파트너)</span></span>
<span class="line"><span>   - 마케팅 전략</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 필요 투자 &amp; 일정</span></span>
<span class="line"><span>   - 초기 투자 (인력, 인프라, 마케팅)</span></span>
<span class="line"><span>   - 18개월 로드맵 (3개월 단위)</span></span>
<span class="line"><span>   - 팀 구성안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 리스크 &amp; 완화 방안</span></span>
<span class="line"><span>   - 기술 리스크, 시장 리스크, 운영 리스크</span></span>
<span class="line"><span>   - 각각의 완화 전략</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8. 재무 전망 (3년)</span></span>
<span class="line"><span>   - 매출, 비용, 영업이익 추정</span></span>
<span class="line"><span>   - 보수적 / 기본 / 낙관적 시나리오</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`proposals/ai-accounting-saas-proposal.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>핵심: CEO가 읽고 &quot;투자 승인&quot;할 만한 설득력. </span></span>
<span class="line"><span>숫자는 현실적으로 — 과도한 낙관은 오히려 신뢰를 깎는다.</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] TAM/SAM/SOM 산정의 논리적 근거</li><li>[ ] 경쟁 분석의 정확성 (더존, 위하고 등 실제 시장 반영)</li><li>[ ] 가격 정책의 현실성 (중소기업 예산 수준)</li><li>[ ] CAC/LTV 추정의 합리성</li><li>[ ] 재무 전망 3개 시나리오의 차이 설득력</li><li>[ ] 리스크 식별의 포괄성</li><li>[ ] 전체 설득력 (CEO 관점에서)</li></ul><hr><h2 id="ps-02-예산-기획안" tabindex="-1">PS-02. 예산 기획안 ⭐⭐ <a class="header-anchor" href="#ps-02-예산-기획안" aria-label="Permalink to &quot;PS-02. 예산 기획안 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-1" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-1" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>다음 분기/연간 예산을 기획하고 정당화하는 문서.</p><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>마케팅팀 2024년 하반기 예산 기획안을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>현황:</span></span>
<span class="line"><span>- 상반기 예산: 총 3억원</span></span>
<span class="line"><span>  - 디지털 광고: 1.5억 (Google 40%, Meta 35%, Naver 25%)</span></span>
<span class="line"><span>  - 콘텐츠 제작: 5천만원 (블로그, 영상, 소셜)</span></span>
<span class="line"><span>  - 이벤트/행사: 5천만원 (온라인 웨비나 3회, 오프라인 세미나 1회)</span></span>
<span class="line"><span>  - 브랜딩: 3천만원 (BI 리뉴얼, 홍보물)</span></span>
<span class="line"><span>  - 툴/SW: 2천만원 (HubSpot, Canva, 분석 도구)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 상반기 성과:</span></span>
<span class="line"><span>  - 리드 생성: 2,400건 (목표 2,000건, 120% 달성)</span></span>
<span class="line"><span>  - MQL→SQL 전환: 18% (목표 15%)</span></span>
<span class="line"><span>  - 웹사이트 트래픽: 월 평균 5만 세션 (+40% YoY)</span></span>
<span class="line"><span>  - 디지털 광고 ROAS: Google 3.2x, Meta 2.1x, Naver 1.4x</span></span>
<span class="line"><span>  - 브랜드 인지도: 타겟 시장 내 12% → 18%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 하반기 목표 (경영진 지시):</span></span>
<span class="line"><span>  - 리드 생성: 3,600건 (+50%)</span></span>
<span class="line"><span>  - 브랜드 인지도: 25% 달성</span></span>
<span class="line"><span>  - 신규 시장(일본) 진출 마케팅 시작</span></span>
<span class="line"><span>  - 전체 예산: 상반기 대비 20% 이내 증가 (최대 3.6억)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>기획안 구성:</span></span>
<span class="line"><span>1. 상반기 성과 요약 &amp; 인사이트</span></span>
<span class="line"><span>   - 채널별 ROI 분석</span></span>
<span class="line"><span>   - 가장 효과적이었던 것 / 비효율적이었던 것</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>2. 하반기 예산 배분안</span></span>
<span class="line"><span>   - 채널별 예산 테이블 (상반기 대비 증감 표시)</span></span>
<span class="line"><span>   - 각 배분의 근거 (데이터 기반)</span></span>
<span class="line"><span>   - Naver 비효율 → 예산 축소 or 최적화?</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. 신규 투자 항목</span></span>
<span class="line"><span>   - 일본 시장 진출 마케팅 (얼마, 어떤 채널)</span></span>
<span class="line"><span>   - AI 도구 도입 (콘텐츠 자동화로 제작비 절감 가능?)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>4. 시나리오 분석</span></span>
<span class="line"><span>   - 기본안 (3.6억)</span></span>
<span class="line"><span>   - 공격적 (4억 — 추가 투자의 예상 효과)</span></span>
<span class="line"><span>   - 보수적 (3.2억 — 어디를 줄일 것인가)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>5. KPI &amp; 측정 계획</span></span>
<span class="line"><span>   - 월별 마일스톤</span></span>
<span class="line"><span>   - 예산 재조정 기준 (어떤 지표가 X 이하면 재배분)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`budgets/marketing-h2-2024-budget.md\`</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 상반기 데이터 분석의 깊이 (ROAS 기반 채널 효율 분석)</li><li>[ ] Naver ROAS 1.4x에 대한 판단 (축소 vs 최적화, 근거)</li><li>[ ] 일본 시장 예산 책정의 현실성</li><li>[ ] 3개 시나리오 간 차이의 합리성</li><li>[ ] 예산 재조정 기준의 구체성 (단순 &quot;모니터링&quot;이 아닌 트리거 조건)</li><li>[ ] 전체 3.6억 한도 내 배분의 설득력</li><li>[ ] 표와 수치의 정확성 (합계 검증)</li></ul><hr><h2 id="ps-03-rfp-응답서" tabindex="-1">PS-03. RFP 응답서 ⭐⭐⭐ <a class="header-anchor" href="#ps-03-rfp-응답서" aria-label="Permalink to &quot;PS-03. RFP 응답서 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-2" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-2" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객의 RFP(제안요청서)에 대응하는 제안서. 수주 여부가 갈리는 핵심 문서.</p><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 RFP에 대한 응답 제안서를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>고객 RFP 요약:</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>발주처: H대학교 (학생 2만명, 교직원 3천명)</span></span>
<span class="line"><span>사업명: 통합 학사행정시스템 고도화</span></span>
<span class="line"><span>예산: 8억원 (VAT 별도)</span></span>
<span class="line"><span>기간: 계약일로부터 12개월</span></span>
<span class="line"><span>현황: 10년 된 자체 개발 시스템 (Java/Oracle), 유지보수 어려움</span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span>1. 기존 시스템 데이터 마이그레이션 (학생 정보 10년치)</span></span>
<span class="line"><span>2. 수강신청 시스템 리뉴얼 (동시접속 5,000명 처리)</span></span>
<span class="line"><span>3. 성적/학사 관리 모듈 재개발</span></span>
<span class="line"><span>4. 모바일 앱 (iOS/Android)</span></span>
<span class="line"><span>5. LMS(학습관리시스템) 연동</span></span>
<span class="line"><span>6. 관리자 대시보드</span></span>
<span class="line"><span>평가 기준: 기술 점수 60% + 가격 점수 40%</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>우리 회사 정보:</span></span>
<span class="line"><span>- SI 전문기업, 교육 분야 프로젝트 5건 수행 경험</span></span>
<span class="line"><span>- 자체 학사행정 플랫폼 &quot;EduCore&quot; 보유 (커스터마이징 가능)</span></span>
<span class="line"><span>- 강점: 수강신청 대용량 처리 기술 (이전 프로젝트에서 동시접속 8,000명 처리 경험)</span></span>
<span class="line"><span>- 약점: 모바일 앱 자체 개발 경험 적음 (외주 파트너 활용 예정)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제안서 구성:</span></span>
<span class="line"><span>1. 회사 소개 &amp; 수행 실적 (교육 분야 강조)</span></span>
<span class="line"><span>2. 사업 이해도 (고객의 현재 문제를 우리가 이해하고 있다는 것)</span></span>
<span class="line"><span>3. 기술 제안</span></span>
<span class="line"><span>   - 전체 아키텍처</span></span>
<span class="line"><span>   - 모듈별 구현 방안</span></span>
<span class="line"><span>   - 수강신청 대용량 처리 기술 상세 (차별화 포인트!)</span></span>
<span class="line"><span>   - 데이터 마이그레이션 전략</span></span>
<span class="line"><span>   - 모바일 앱 개발 방안 (약점을 어떻게 보완하는지)</span></span>
<span class="line"><span>4. 프로젝트 관리 방안</span></span>
<span class="line"><span>   - 일정표 (12개월, 월별)</span></span>
<span class="line"><span>   - 투입 인력 (역할별 MM)</span></span>
<span class="line"><span>   - 리스크 관리 계획</span></span>
<span class="line"><span>   - 품질 관리 (테스트 전략)</span></span>
<span class="line"><span>5. 유지보수 &amp; 기술 이전 방안</span></span>
<span class="line"><span>6. 견적 (8억 내, 항목별 상세)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`proposals/h-university-rfp-response.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>핵심: </span></span>
<span class="line"><span>- 기술 점수 60%를 최대화하는 전략</span></span>
<span class="line"><span>- 수강신청 대용량 처리를 차별화 무기로 활용</span></span>
<span class="line"><span>- 모바일 앱 약점을 &quot;오히려 전문 파트너 협업이 품질이 높다&quot;로 전환</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 사업 이해도 섹션의 깊이 (대학 행정 맥락 이해)</li><li>[ ] 수강신청 대용량 처리 기술 차별화의 구체성</li><li>[ ] 모바일 앱 약점의 설득력 있는 보완 논리</li><li>[ ] 12개월 일정의 현실성 (8억 규모 SI)</li><li>[ ] 투입 인력 MM 산정의 합리성</li><li>[ ] 견적 8억 내 항목별 배분</li><li>[ ] 전반적인 제안서의 전문성과 신뢰감</li></ul><hr><h2 id="ps-04-swot-분석-전략-수립" tabindex="-1">PS-04. SWOT 분석 &amp; 전략 수립 ⭐⭐ <a class="header-anchor" href="#ps-04-swot-분석-전략-수립" aria-label="Permalink to &quot;PS-04. SWOT 분석 &amp; 전략 수립 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-3" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-3" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>현황 분석 프레임워크를 활용한 전략 도출.</p><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 정보로 SWOT 분석을 하고 전략을 수립해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: 국내 중소 화장품 브랜드 &quot;글로우랩&quot;</span></span>
<span class="line"><span>- 설립 5년차, 직원 45명, 매출 120억</span></span>
<span class="line"><span>- 온라인 D2C(자사몰) 60%, 올리브영 30%, 기타 10%</span></span>
<span class="line"><span>- 주력: 비건 스킨케어 라인 (클렌저, 토너, 세럼)</span></span>
<span class="line"><span>- 특징: 자체 R&amp;D팀(5명) 보유, 비건 인증 획득</span></span>
<span class="line"><span>- 재무: 영업이익률 8%, 현금 15억 보유</span></span>
<span class="line"><span>- 최근 이슈: 올리브영 매출 정체, 자사몰 성장 둔화</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시장 정보:</span></span>
<span class="line"><span>- 국내 화장품 시장: 15조원, 성장률 3%</span></span>
<span class="line"><span>- 비건/클린뷰티: 전체의 8%, 성장률 25%</span></span>
<span class="line"><span>- 경쟁: 대기업(아모레, LG생건)이 비건 라인 출시 시작</span></span>
<span class="line"><span>- 해외: K-뷰티 수출 20% 성장 (일본, 동남아)</span></span>
<span class="line"><span>- 소비 트렌드: MZ세대 → 가치 소비, 성분 중시</span></span>
<span class="line"><span>- 위협: 중국 C-뷰티 급성장, 원료 가격 상승 (20%)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`strategy/swot-analysis.md\` — SWOT 분석</span></span>
<span class="line"><span>   - 각 영역 5개 이상 항목</span></span>
<span class="line"><span>   - 단순 나열이 아닌, 각 항목에 근거/데이터 포함</span></span>
<span class="line"><span>   - SWOT 매트릭스 테이블</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`strategy/strategic-directions.md\` — 전략 방향</span></span>
<span class="line"><span>   - SO 전략 (강점×기회): 공격적 성장</span></span>
<span class="line"><span>   - WO 전략 (약점×기회): 약점 보완하며 기회 포착</span></span>
<span class="line"><span>   - ST 전략 (강점×위협): 방어적 활용</span></span>
<span class="line"><span>   - WT 전략 (약점×위협): 리스크 최소화</span></span>
<span class="line"><span>   - 각 전략에 구체적인 실행 방안 2~3개</span></span>
<span class="line"><span>   - 우선순위 매트릭스 (영향도 × 실행 용이성)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`strategy/action-plan-q3.md\` — 다음 분기 실행 계획</span></span>
<span class="line"><span>   - 전략 방향에서 선택한 Top 3 실행안</span></span>
<span class="line"><span>   - 각 실행안별: 목표, 담당, 예산, KPI, 일정</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] SWOT 항목의 구체성 (추상적 &quot;시장 성장&quot; 아닌 &quot;비건 25% 성장&quot;)</li><li>[ ] 강점과 약점의 솔직한 구분 (자사몰 의존, 해외 미진출 등)</li><li>[ ] SO/WO/ST/WT 전략의 논리적 연결</li><li>[ ] 실행 방안의 구체성과 현실성 (45명 회사 규모 고려)</li><li>[ ] 우선순위 판단의 합리성</li><li>[ ] 예산 15억 현금을 고려한 투자 제안</li></ul><hr><h2 id="ps-05-비즈니스-사례-분석-case-study" tabindex="-1">PS-05. 비즈니스 사례 분석 (Case Study) ⭐⭐ <a class="header-anchor" href="#ps-05-비즈니스-사례-분석-case-study" aria-label="Permalink to &quot;PS-05. 비즈니스 사례 분석 (Case Study) :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-4" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-4" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객사에 보여줄 성공 사례 문서. 마케팅 + 영업 지원 자료로 활용.</p><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 정보로 고객 성공 사례(Case Study)를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>프로젝트 정보:</span></span>
<span class="line"><span>- 고객: J물류 (중견 물류기업, 직원 800명, 매출 2,000억)</span></span>
<span class="line"><span>- 우리 솔루션: 물류 최적화 AI 플랫폼 &quot;RouteMaster&quot;</span></span>
<span class="line"><span>- 도입 기간: 2023년 7월 ~ 2024년 1월 (6개월)</span></span>
<span class="line"><span>- 배경: 배송 기사 150명, 일 평균 배송 8,000건</span></span>
<span class="line"><span>  수작업으로 배차·경로 계획 → 비효율, 기사 불만, 고객 클레임</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>도입 결과:</span></span>
<span class="line"><span>- 배송 효율: 평균 배송 시간 42분 → 31분 (26% 단축)</span></span>
<span class="line"><span>- 연료비: 월 2.3억 → 1.7억 (26% 절감, 연 7.2억 절감)</span></span>
<span class="line"><span>- 고객 만족도: 배송 정시율 78% → 94%</span></span>
<span class="line"><span>- 기사 만족도: 3.2/5 → 4.1/5</span></span>
<span class="line"><span>- 클레임: 월 평균 120건 → 35건 (71% 감소)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>작성할 문서:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`case-studies/j-logistics.md\` — 전체 케이스 스터디</span></span>
<span class="line"><span>   구성:</span></span>
<span class="line"><span>   - 핵심 성과 요약 (수치 3개, 눈에 띄게)</span></span>
<span class="line"><span>   - 고객 소개 &amp; 도전 과제</span></span>
<span class="line"><span>   - &quot;왜 RouteMaster를 선택했나&quot; (의사결정 과정)</span></span>
<span class="line"><span>   - 도입 과정 (6개월 타임라인)</span></span>
<span class="line"><span>   - 도입 중 어려웠던 점 &amp; 해결 (현실감)</span></span>
<span class="line"><span>   - 정량적 성과</span></span>
<span class="line"><span>   - 고객 인용문 (가상이지만 자연스럽게, 물류팀장과 CEO)</span></span>
<span class="line"><span>   - 향후 계획 (2단계 도입 예정)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`case-studies/j-logistics-onepager.md\` — 1페이지 요약본</span></span>
<span class="line"><span>   - 영업팀이 미팅에서 보여줄 용도</span></span>
<span class="line"><span>   - 그래프/차트 대신 볼드 숫자 + 한 줄 설명</span></span>
<span class="line"><span>   - 인쇄해도 보기 좋은 레이아웃</span></span>
<span class="line"><span></span></span>
<span class="line"><span>톤: 광고처럼 과장하지 말고, 데이터가 말하게 해줘.</span></span>
<span class="line"><span>&quot;어려웠던 점&quot;을 포함해야 신뢰도가 올라간다.</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 핵심 수치의 시각적 강조</li><li>[ ] &quot;왜 선택했나&quot; 섹션의 설득력</li><li>[ ] 어려웠던 점 포함 여부 (신뢰도 핵심)</li><li>[ ] 고객 인용문의 자연스러움 (광고체 아닌 실제 말투)</li><li>[ ] 1페이지 요약의 밀도와 가독성</li><li>[ ] 전체적으로 &quot;광고&quot;가 아닌 &quot;사례 분석&quot; 톤 유지</li><li>[ ] 정량 데이터의 정확한 인용</li></ul><hr><h2 id="ps-06-사업-계속-중단-의사결정-보고서" tabindex="-1">PS-06. 사업 계속/중단 의사결정 보고서 ⭐⭐⭐ <a class="header-anchor" href="#ps-06-사업-계속-중단-의사결정-보고서" aria-label="Permalink to &quot;PS-06. 사업 계속/중단 의사결정 보고서 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-5" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-5" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>감정이 아닌 데이터로 어려운 의사결정을 지원하는 문서.</p><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 사업의 계속/중단 여부를 판단하는 의사결정 보고서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>사업 개요:</span></span>
<span class="line"><span>- 사업명: &quot;EduPlay&quot; — 초등학생 대상 교육용 게임 앱</span></span>
<span class="line"><span>- 출시: 2022년 9월 (2년 운영)</span></span>
<span class="line"><span>- 초기 투자: 8억원 (개발 5억 + 마케팅 3억)</span></span>
<span class="line"><span>- 현재 팀: PM 1, 개발 3, 디자이너 1, 마케팅 1 (총 6명)</span></span>
<span class="line"><span>- 월 운영비: 약 4,500만원 (인건비 3,800 + 서버 400 + 기타 300)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>성과:</span></span>
<span class="line"><span>- MAU: 출시 초 15만 → 현재 3.2만 (79% 감소)</span></span>
<span class="line"><span>- 유료 전환: 2.1% (업계 평균 5%)</span></span>
<span class="line"><span>- 월 매출: 약 850만원 (인앱결제 600 + 광고 250)</span></span>
<span class="line"><span>- 월 적자: 약 3,650만원</span></span>
<span class="line"><span>- 누적 적자: 약 5.5억원 (초기 투자 포함 총 13.5억)</span></span>
<span class="line"><span>- 앱스토어 평점: 4.3/5 (리뷰 1,200개, 내용은 긍정적)</span></span>
<span class="line"><span>- 이탈 사유: 주로 &quot;콘텐츠 부족&quot; (같은 게임 반복)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시장 상황:</span></span>
<span class="line"><span>- 국내 에듀테크 시장 성장 중 (연 15%)</span></span>
<span class="line"><span>- 경쟁: 대기업 진출 (카카오키즈, 네이버 교육), 해외 앱</span></span>
<span class="line"><span>- 기회: 교육부 디지털 교과서 정책 (2025년 확대)</span></span>
<span class="line"><span>- B2B 가능성: 학교/학원에 단체 라이센스 판매 (아직 미시도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>옵션:</span></span>
<span class="line"><span>A) 현 상태 유지 (월 3,650만원 적자 지속)</span></span>
<span class="line"><span>B) 추가 투자 (3억원, 콘텐츠 대폭 확충 + B2B 영업팀 구성)</span></span>
<span class="line"><span>C) 축소 운영 (개발 1명만 유지, 신규 개발 중단, 월 운영비 1,200만원)</span></span>
<span class="line"><span>D) 사업 중단 (앱 무료 전환 후 유지만, 팀 해산)</span></span>
<span class="line"><span>E) 매각/합병 (에듀테크 기업에 기술+사용자 매각)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>보고서:</span></span>
<span class="line"><span>1. 현황 분석 요약 (데이터 기반, 감정 배제)</span></span>
<span class="line"><span>2. 각 옵션별 분석</span></span>
<span class="line"><span>   - 예상 비용 (12개월 기준)</span></span>
<span class="line"><span>   - 예상 결과 (best/worst/base case)</span></span>
<span class="line"><span>   - 리스크</span></span>
<span class="line"><span>   - 기회비용 (이 팀원들이 다른 프로젝트를 하면?)</span></span>
<span class="line"><span>3. 추천안 &amp; 근거</span></span>
<span class="line"><span>4. 실행 계획 (추천안 선택 시)</span></span>
<span class="line"><span>5. 의사결정 데드라인</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`decisions/eduplay-continuation-analysis.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>핵심: 이 사업에 개인적 애착이 있는 PM과 CEO가 읽을 문서.</span></span>
<span class="line"><span>감정적 판단을 유도하지 않되, 냉정한 팩트만으로 난도질하지도 말 것.</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 데이터 분석의 객관성 (감정적 표현 배제)</li><li>[ ] 5가지 옵션 각각의 분석 깊이</li><li>[ ] 기회비용 분석의 포함 여부 (6명이 다른 프로젝트를 하면?)</li><li>[ ] B2B 피벗 가능성에 대한 현실적 평가</li><li>[ ] 추천안의 논리적 일관성 (데이터 → 결론)</li><li>[ ] &quot;앱스토어 4.3점, 리뷰 긍정적&quot;이라는 긍정 신호를 어떻게 다루는지</li><li>[ ] 톤: 냉정하지만 공감적 (PM의 노력을 인정하면서도 팩트 전달)</li></ul><hr><h2 id="ps-07-프로세스-개선-제안서" tabindex="-1">PS-07. 프로세스 개선 제안서 ⭐⭐ <a class="header-anchor" href="#ps-07-프로세스-개선-제안서" aria-label="Permalink to &quot;PS-07. 프로세스 개선 제안서 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-6" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-6" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>현재 업무 프로세스의 비효율을 분석하고 개선안을 제시하는 문서.</p><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>우리 회사 고객 문의 처리 프로세스 개선안을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>현재 프로세스 (As-Is):</span></span>
<span class="line"><span>1. 고객이 문의 → 대표 이메일(info@) 수신</span></span>
<span class="line"><span>2. 관리팀 사원이 수동으로 이메일 확인 (하루 2~3회)</span></span>
<span class="line"><span>3. 내용 보고 담당 부서 판단 → 해당 부서 담당자에게 이메일 전달</span></span>
<span class="line"><span>4. 담당자가 확인 후 답변 작성 → 관리팀에 회신</span></span>
<span class="line"><span>5. 관리팀이 고객에게 최종 답변 발송</span></span>
<span class="line"><span></span></span>
<span class="line"><span>문제점 (팀장이 말한 것):</span></span>
<span class="line"><span>- &quot;응답이 너무 느려요. 평균 2~3일 걸림. 고객 불만 많아요.&quot;</span></span>
<span class="line"><span>- &quot;담당 부서를 잘못 배정하는 경우가 한 달에 10건은 돼요.&quot;</span></span>
<span class="line"><span>- &quot;같은 질문이 반복되는데 매번 새로 답변 써요.&quot;</span></span>
<span class="line"><span>- &quot;주말에 들어온 문의는 월요일에야 확인해요.&quot;</span></span>
<span class="line"><span>- &quot;문의 현황 파악이 안 돼요. 누가 뭘 처리 중인지 모름.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>추가 정보:</span></span>
<span class="line"><span>- 월 평균 문의: 약 400건</span></span>
<span class="line"><span>- 유형 분포: 제품 문의 40%, 기술 지원 25%, 결제/환불 20%, 기타 15%</span></span>
<span class="line"><span>- 직원: 관리팀 2명, 각 부서 담당자 5명이 문의 응대</span></span>
<span class="line"><span>- 예산: 월 200만원 이내 (도구 도입 가능)</span></span>
<span class="line"><span>- 기술 수준: 직원들이 기술에 익숙하지 않음 (쉬운 도구 필요)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>만들어야 할 문서:</span></span>
<span class="line"><span>1. \`process/customer-inquiry-improvement.md\`</span></span>
<span class="line"><span>   - As-Is 프로세스 다이어그램 (텍스트 기반 플로우)</span></span>
<span class="line"><span>   - 문제점 분석 (근본 원인 분석, 5 Whys)</span></span>
<span class="line"><span>   - To-Be 프로세스 설계</span></span>
<span class="line"><span>   - 도구 추천 (월 200만원 이내, 비기술자 사용 가능)</span></span>
<span class="line"><span>   - 기대 효과 (응답 시간, 오배정률, 반복 문의 등 수치로)</span></span>
<span class="line"><span>   - 도입 일정 (4주)</span></span>
<span class="line"><span>   - 변화 관리 (직원 교육, 저항 관리)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;현실성&quot;이 핵심이야. 대기업용 솔루션을 추천하면 안 되고,</span></span>
<span class="line"><span>7명이 쓸 수 있는 현실적 방안이어야 해.</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] As-Is 프로세스 분석의 정확성</li><li>[ ] 5 Whys 분석의 깊이 (표면 문제 → 근본 원인)</li><li>[ ] To-Be 프로세스의 현실성 (7명 규모에 맞는)</li><li>[ ] 도구 추천의 현실성 (Freshdesk, Zendesk, 채널톡 등 + 가격)</li><li>[ ] FAQ/자동 응답 도입 제안 여부</li><li>[ ] 변화 관리 섹션의 실용성 (직원 저항 대응)</li><li>[ ] 기대 효과 수치의 합리성</li></ul><hr><h2 id="ps-08-경쟁사-분석-보고서" tabindex="-1">PS-08. 경쟁사 분석 보고서 ⭐⭐ <a class="header-anchor" href="#ps-08-경쟁사-분석-보고서" aria-label="Permalink to &quot;PS-08. 경쟁사 분석 보고서 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-7" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-7" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>영업/전략팀이 활용할 경쟁사 분석 자료.</p><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>경쟁사 분석 보고서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>우리 회사: 중소기업 대상 프로젝트 관리 SaaS &quot;TaskFlow&quot;</span></span>
<span class="line"><span>- 출시 2년, MAU 5,000, 유료 고객 800사</span></span>
<span class="line"><span>- 가격: 월 인당 8,000원</span></span>
<span class="line"><span>- 강점: 한국어 UI, 간편한 간트차트, 카카오톡 연동</span></span>
<span class="line"><span>- 약점: 모바일 앱 미흡, 외부 연동 적음, 영문 미지원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>경쟁사 5개를 분석해줘:</span></span>
<span class="line"><span>1. Notion — 올인원 워크스페이스</span></span>
<span class="line"><span>2. Monday.com — 프로젝트 관리 전문</span></span>
<span class="line"><span>3. Jira — 개발팀 특화</span></span>
<span class="line"><span>4. 플로우(Flow) — 국내 프로젝트 관리</span></span>
<span class="line"><span>5. 콜라비(Collabee) — 국내 협업 도구</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 항목 (각 경쟁사별):</span></span>
<span class="line"><span>1. 제품 개요 &amp; 포지셔닝</span></span>
<span class="line"><span>2. 가격 정책 (상세 tier 비교)</span></span>
<span class="line"><span>3. 핵심 기능 비교 매트릭스 (O/X/△ 표)</span></span>
<span class="line"><span>4. 타깃 고객 (규모, 산업, 사용 사례)</span></span>
<span class="line"><span>5. 강점 &amp; 약점</span></span>
<span class="line"><span>6. 최근 동향 (신규 기능, 투자, 파트너십)</span></span>
<span class="line"><span>7. 우리와의 직접 경쟁 정도 (상/중/하)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>종합 분석:</span></span>
<span class="line"><span>- 우리의 경쟁 우위 &amp; 취약점</span></span>
<span class="line"><span>- 포지셔닝 맵 (가격 × 기능 풍부도)</span></span>
<span class="line"><span>- &quot;이 고객에게는 우리가 유리하다&quot; 구체적 세그먼트 3개</span></span>
<span class="line"><span>- 영업팀이 경쟁사 비교 질문 받았을 때 쓸 수 있는 Battle Card</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`analysis/competitor-analysis-taskflow.md\`</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 5개 경쟁사 정보의 정확성</li><li>[ ] 기능 비교 매트릭스의 공정성 (우리 편향 없이)</li><li>[ ] 가격 비교의 상세도 (tier별, 인당 계산)</li><li>[ ] 포지셔닝 맵의 합리성</li><li>[ ] Battle Card의 실용성 (영업 현장에서 바로 사용 가능)</li><li>[ ] &quot;이 세그먼트에서 우리가 유리&quot; 분석의 구체성</li><li>[ ] 전반적인 객관성 유지</li></ul>`,70)])])}const q=a(e,[["render",i]]);export{u as __pageData,q as default};
